const TRANSLATIONS: Record<AppLanguage, Messages> = { ja, en, zh, ko, es };

export function isAppLanguage(value: string | null): value is AppLanguage {
  return LANGUAGE_OPTIONS.some((option) => option.code === value);
}

export function localeFor(language: AppLanguage) {
  return { ja: "ja-JP", en: "en-US", zh: "zh-CN", ko: "ko-KR", es: "es-ES" }[language];
}

export function translate(language: AppLanguage, key: TranslationKey, values: Record<string, string | number> = {}) {
  return Object.entries(values).reduce(
    (message, [name, value]) => message.replaceAll(`{${name}}`, String(value)),
    TRANSLATIONS[language][key]
  );
}

export const WAITING_MESSAGE_KEYS = ["waiting.1", "waiting.2", "waiting.3", "waiting.4", "waiting.5", "waiting.6", "waiting.7", "waiting.8"] as const;

export type Translate = (key: TranslationKey, values?: Record<string, string | number>) => string;
